var maxGeneticDifference = function(parents, queries) {
    const n = parents.length;
    const BITS = 18;
    const children = Array.from({length: n}, () => []);
    let root = -1;
    for (let i = 0; i < n; i++) {
        if (parents[i] === -1) root = i;
        else children[parents[i]].push(i);
    }
    const qby = Array.from({length: n}, () => []);
    for (let qi = 0; qi < queries.length; qi++) {
        qby[queries[qi][0]].push([queries[qi][1], qi]);
    }
    const ans = new Array(queries.length).fill(0);
    const trie = [[0, 0]];
    const cnt = [0];
    function insert(x, delta) {
        let cur = 0;
        cnt[cur] += delta;
        for (let b = BITS; b >= 0; b--) {
            const bit = (x >> b) & 1;
            if (trie[cur][bit] === 0) {
                trie.push([0, 0]);
                cnt.push(0);
                trie[cur][bit] = trie.length - 1;
            }
            cur = trie[cur][bit];
            cnt[cur] += delta;
        }
    }
    function query(x) {
        let cur = 0, res = 0;
        for (let b = BITS; b >= 0; b--) {
            const bit = (x >> b) & 1;
            const want = 1 - bit;
            const nxt = trie[cur][want];
            if (nxt !== 0 && cnt[nxt] > 0) {
                res |= (1 << b);
                cur = nxt;
            } else {
                cur = trie[cur][bit];
                if (cur === 0) break;
            }
        }
        return res;
    }
    const stack = [[root, 0]];
    insert(root, 1);
    while (stack.length) {
        const top = stack[stack.length - 1];
        const node = top[0];
        const ci = top[1];
        if (ci === 0) {
            for (const [val, qi] of qby[node]) ans[qi] = query(val);
        }
        if (ci < children[node].length) {
            top[1] = ci + 1;
            const child = children[node][ci];
            insert(child, 1);
            stack.push([child, 0]);
        } else {
            insert(node, -1);
            stack.pop();
        }
    }
    return ans;
};
